// Extract channel from filename
const file = $input.item.json;

// Validate input
if (!file || !file.name) {
  throw new Error('No file data received from trigger');
}

const name = file.name.toLowerCase();

// Determine channel
let channel = "UNKNOWN";
if (name.includes("health")) {
  channel = "HEALTH_HACKS";
} else if (name.includes("money")) {
  channel = "MONEYSTACK";
}

// Validate file type
const validExtensions = ['mp4', 'mov', 'avi', 'webm'];
const hasValidExtension = validExtensions.some(ext => name.endsWith(ext));

if (!hasValidExtension) {
  throw new Error(`Invalid file type. Must be: ${validExtensions.join(', ')}`);
}

// Generate unique video ID
const timestamp = new Date().toISOString().split('T')[0].replace(/-/g, '');
const randomId = Math.random().toString(36).substring(2, 8);
const videoId = `${channel.toLowerCase()}-${timestamp}-${randomId}`;

// Return structured data
return {
  videoId: videoId,
  channel: channel,
  filename: file.name,
  driveId: file.id,
  mimeType: file.mimeType || 'video/mp4',
  size: file.size || 0,
  detectedAt: new Date().toISOString()
};

// Build prompt for Claude
const channel = $node['Extract Channel Info'].json.channel;
const transcript = $json.text;
const filename = $node['Extract Channel Info'].json.filename;

// Build comprehensive prompt
const prompt = `You are a social media content strategist. Generate unique, platform-optimized titles and descriptions for this video.

CHANNEL: ${channel}
FILENAME: ${filename}
TRANSCRIPT: ${transcript}

Generate 3 DIFFERENT variations tailored to each platform:

**TIKTOK:**
- Title: Viral hook (first 3 words grab attention)
- Caption: 2-3 sentences, casual tone, emoji-rich
- Hashtags: 5-7 trending + niche tags

**INSTAGRAM:**
- Title: Aspirational/inspirational angle
- Caption: Story format, 3-4 sentences, relatable
- Hashtags: 10-15 mixed (trending + niche + community)

**YOUTUBE:**
- Title: SEO-optimized (include main keyword)
- Description: Educational format, 4-5 sentences, include CTA
- Tags: 10-12 keywords (mix broad + specific)

OUTPUT ONLY VALID JSON (no markdown, no explanation):
{
  "tiktok": {
    "title": "",
    "caption": "",
    "hashtags": []
  },
  "instagram": {
    "title": "",
    "caption": "",
    "hashtags": []
  },
  "youtube": {
    "title": "",
    "description": "",
    "tags": []
  }
}`;

return {
  prompt: prompt,
  channel: channel,
  videoId: $node['Extract Channel Info'].json.videoId
};

// Parse and validate Claude response
const response = $json.choices[0].message.content;
let content;

try {
  // Try direct parse first
  content = JSON.parse(response);
} catch (error) {
  // Try cleaning markdown wrapper
  const cleaned = response
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  try {
    content = JSON.parse(cleaned);
  } catch (error2) {
    throw new Error(`Failed to parse Claude response: ${error2.message}`);
  }
}

// Validate structure
if (!content.tiktok || !content.instagram || !content.youtube) {
  throw new Error('Invalid content structure from Claude');
}

// Return clean structured data
return {
  tiktok: content.tiktok,
  instagram: content.instagram,
  youtube: content.youtube,
  parsedAt: new Date().toISOString()
};

// Build complete metadata object
const metadata = {
  video_id: $node['Extract Channel Info'].json.videoId,
  channel: $node['Extract Channel Info'].json.channel,
  filename: $node['Extract Channel Info'].json.filename,
  drive_id: $node['Extract Channel Info'].json.driveId,
  transcription: $node['Whisper Transcribe'].json.text,
  content: {
    tiktok: $json.tiktok,
    instagram: $json.instagram,
    youtube: $json.youtube
  },
  metadata: {
    size: $node['Extract Channel Info'].json.size,
    mime_type: $node['Extract Channel Info'].json.mimeType,
    detected_at: $node['Extract Channel Info'].json.detectedAt
  },
  created_at: new Date().toISOString()
};

// Save to disk
const fs = require('fs');
const dir = '/workspace/.state/videos';

// Create directory if doesn't exist
if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

// Write metadata file
const filepath = `${dir}/${metadata.video_id}.json`;
fs.writeFileSync(filepath, JSON.stringify(metadata, null, 2));

// Return for next node
return { json: metadata };

